// syncTriggerDirect v7.1 — sync + upsert + pointer + live progress

let sdk = null;
let sdkAvailable = false;
try {
  sdk = require('mitra-sdk');
  sdkAvailable = true;
} catch (e) {}

const MOVIDESK_URL = 'https://api.movidesk.com/public/v1';
const mode = (event.mode || 'INCREMENTAL').toUpperCase();
const token = event.token || '';
const lastSync = event.lastSync || '';
const startDate = event.startDate || '';
const pageSize = parseInt(event.pageSize) || 50;
const maxPages = parseInt(event.maxPages) || 10;
const pjId = parseInt(event.projectId) || 0;
const source = event.source || 'external';
const session = 'S' + Date.now().toString(36).toUpperCase();
const execStart = Date.now();
const TIMEOUT_MS = 90000;

if (!token) {
  return { success: false, error: 'Token Movidesk nao configurado', session, sdkAvailable };
}

function clean(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/'/g, "''").replace(/\\/g, '\\\\').replace(/[\x00-\x08\x0b\x0c\x0e-\x1f]/g, '');
}
function truncate(s, max) {
  const c = clean(s);
  return c.length > max ? c.substring(0, max) : c;
}

async function setLiveProgress(data) {
  if (!sdkAvailable || !sdk || !pjId) return;
  try {
    await sdk.setVariableMitra({
      projectId: pjId,
      key: 'SYNC_LIVE_PROGRESS',
      value: JSON.stringify({ ...data, ts: new Date().toISOString().slice(11, 19), session })
    });
  } catch (e) {}
}

async function insertLog(tipo, mensagem, detalhes) {
  if (!sdkAvailable || !sdk || !pjId) return;
  try {
    await sdk.runDmlMitra({
      projectId: pjId,
      sql: "INSERT INTO SYNC_LOG (TIPO, MENSAGEM, DETALHES, DATA) VALUES ('" + truncate(tipo, 30) + "', '" + truncate(mensagem, 500) + "', '" + truncate(detalhes, 2000) + "', '" + new Date().toISOString().slice(0, 19) + "')"
    });
  } catch (e) {}
}

function isTimedOut() {
  return (Date.now() - execStart) > TIMEOUT_MS;
}

await setLiveProgress({ stage: 'STARTING', tickets: 0, pages: 0, endpoint: '', message: 'Iniciando ' + mode + '...' });
await insertLog('CYCLE_START', 'Faixa ' + (startDate || 'inicio') + ', modo ' + mode + ', maxPages=' + maxPages, 'session=' + session + ', source=' + source);

const selectFields = 'id,protocol,type,subject,category,urgency,status,baseStatus,origin,createdDate,ownerTeam,serviceFirstLevel,lastUpdate,actionCount,lifeTimeWorkingTime,resolvedIn,closedIn,canceledIn,lastActionDate,slaAgreement,slaAgreementRule,slaSolutionTime,slaResponseTime,resolvedInFirstCall,owner';

const results = [];
let totalTickets = 0;
let totalErrors = 0;
let currentEndpoint = '';
let lastTicketDate = null;
let timedOut = false;
let ticketsPersisted = 0;

async function fetchPage(endpoint, orderBy, filterParam, label, page) {
  const skip = page * pageSize;
  const url = MOVIDESK_URL + '/' + endpoint + '?token=' + token + '&$top=' + pageSize + '&$skip=' + skip + '&$select=' + selectFields + '&$orderby=' + orderBy + (filterParam || '');
  const start = Date.now();
  let responseCode = 0;
  let ticketsCount = 0;
  let error = '';
  try {
    const res = await fetch(url, { signal: AbortSignal.timeout(30000) });
    responseCode = res.status;
    const elapsed = Date.now() - start;
    if (res.status === 429) {
      error = 'Rate limit (429)';
      results.push({ page, label, responseCode, ticketsCount: 0, error, elapsed });
      return { ok: false, retryAfter: 60, tickets: [] };
    }
    if (res.status === 403) {
      error = 'HTTP 403 Forbidden';
      results.push({ page, label, responseCode, ticketsCount: 0, error, elapsed });
      return { ok: false, fatal: true, tickets: [] };
    }
    if (!res.ok) {
      error = 'HTTP ' + res.status;
      results.push({ page, label, responseCode, ticketsCount: 0, error, elapsed });
      return { ok: false, tickets: [] };
    }
    const tickets = await res.json();
    if (!Array.isArray(tickets)) {
      results.push({ page, label, responseCode, ticketsCount: 0, error: 'Not array', elapsed });
      return { ok: true, tickets: [] };
    }
    ticketsCount = tickets.length;
    results.push({ page, label, responseCode, ticketsCount, error: '', elapsed });
    return { ok: true, tickets };
  } catch (e) {
    error = String(e.message || e).substring(0, 200);
    results.push({ page, label, responseCode: 0, ticketsCount: 0, error, elapsed: Date.now() - start });
    return { ok: false, tickets: [] };
  }
}

// ── Persist tickets via UPSERT — column names match REAL TICKETS table ──
async function persistTickets(tickets) {
  if (!sdkAvailable || !sdk || !pjId || tickets.length === 0) return 0;
  let persisted = 0;
  for (const t of tickets) {
    try {
      const id = parseInt(t.id) || 0;
      if (id === 0) continue;
      const proto = truncate(t.protocol || '', 50);
      const assunto = truncate(t.subject || '', 500);
      const cat = truncate(t.category || '', 200);
      const urg = truncate(t.urgency || '', 50);
      const st = truncate(t.status || '', 100);
      const stBase = truncate(t.baseStatus || '', 50);
      const criado = (t.createdDate || '').substring(0, 19);
      const atualizado = (t.lastUpdate || '').substring(0, 19);
      const equipe = truncate(t.ownerTeam || '', 200);
      const nivel1 = truncate(t.serviceFirstLevel || '', 200);
      const qtdAcoes = parseInt(t.actionCount) || 0;
      const tempoVida = truncate(String(t.lifeTimeWorkingTime || ''), 20);
      const resolvido = (t.resolvedIn || '').substring(0, 19);
      const fechado = (t.closedIn || '').substring(0, 19);
      const cancelado = (t.canceledIn || '').substring(0, 19);
      const ultAcao = (t.lastActionDate || '').substring(0, 19);
      const slaAcordo = truncate((t.slaAgreement || ''), 200);
      const slaRegra = truncate((t.slaAgreementRule || ''), 200);
      const slaTempoSol = parseInt(t.slaSolutionTime) || 0;
      const slaTempoResp = parseInt(t.slaResponseTime) || 0;
      const resolvPrimeiro = t.resolvedInFirstCall === true ? 1 : 0;
      const ownerId = truncate((t.owner && t.owner.id) ? String(t.owner.id) : '', 50);
      const ownerNome = truncate((t.owner && t.owner.businessName) || '', 200);
      const ownerEmail = truncate((t.owner && t.owner.email) || '', 200);

      const sql = "INSERT INTO TICKETS (ID, PROTOCOLO, ASSUNTO, CATEGORIA, URGENCIA, STATUS, STATUS_BASE, CRIADO_EM, ATUALIZADO_EM, EQUIPE, SERVICO_NIVEL1, QTD_ACOES, TEMPO_VIDA_MINUTOS, RESOLVIDO_EM, FECHADO_EM, CANCELADO_EM, ULTIMA_ACAO_EM, SLA_ACORDO, SLA_REGRA, SLA_TEMPO_SOLUCAO, SLA_TEMPO_RESPOSTA, RESOLVIDO_PRIMEIRO_CONTATO, OWNER_ID, OWNER_NOME, OWNER_EMAIL) VALUES (" + id + ", '" + proto + "', '" + assunto + "', '" + cat + "', '" + urg + "', '" + st + "', '" + stBase + "', '" + criado + "', '" + atualizado + "', '" + equipe + "', '" + nivel1 + "', " + qtdAcoes + ", '" + tempoVida + "', '" + resolvido + "', '" + fechado + "', '" + cancelado + "', '" + ultAcao + "', '" + slaAcordo + "', '" + slaRegra + "', " + slaTempoSol + ", " + slaTempoResp + ", " + resolvPrimeiro + ", '" + ownerId + "', '" + ownerNome + "', '" + ownerEmail + "') ON DUPLICATE KEY UPDATE PROTOCOLO='" + proto + "', ASSUNTO='" + assunto + "', CATEGORIA='" + cat + "', URGENCIA='" + urg + "', STATUS='" + st + "', STATUS_BASE='" + stBase + "', ATUALIZADO_EM='" + atualizado + "', EQUIPE='" + equipe + "', SERVICO_NIVEL1='" + nivel1 + "', QTD_ACOES=" + qtdAcoes + ", TEMPO_VIDA_MINUTOS='" + tempoVida + "', RESOLVIDO_EM='" + resolvido + "', FECHADO_EM='" + fechado + "', CANCELADO_EM='" + cancelado + "', ULTIMA_ACAO_EM='" + ultAcao + "', SLA_ACORDO='" + slaAcordo + "', SLA_REGRA='" + slaRegra + "', SLA_TEMPO_SOLUCAO=" + slaTempoSol + ", SLA_TEMPO_RESPOSTA=" + slaTempoResp + ", RESOLVIDO_PRIMEIRO_CONTATO=" + resolvPrimeiro + ", OWNER_ID='" + ownerId + "', OWNER_NOME='" + ownerNome + "', OWNER_EMAIL='" + ownerEmail + "'";

      await sdk.runDmlMitra({ projectId: pjId, sql });
      persisted++;
    } catch (e) {
      // One bad record shouldnt stop sync
    }
  }
  return persisted;
}

// ── Filter ──
const isFullSync = mode === 'FULL' || (!lastSync && !startDate);
let filterParam = '';
let effectiveFilterDate = '';

if (!isFullSync) {
  let candidateDates = [];
  if (startDate) candidateDates.push(startDate + 'T00:00:00');
  if (lastSync) {
    const d = new Date(lastSync.endsWith('Z') ? lastSync : lastSync + 'Z');
    d.setMinutes(d.getMinutes() - 2);
    candidateDates.push(d.toISOString().slice(0, 19));
  }
  if (candidateDates.length > 0) {
    effectiveFilterDate = candidateDates.length === 2
      ? (candidateDates[0] < candidateDates[1] ? candidateDates[0] : candidateDates[1])
      : candidateDates[0];
    filterParam = '&$filter=lastUpdate ge ' + effectiveFilterDate + 'z';
  }
} else if (startDate) {
  effectiveFilterDate = startDate + 'T00:00:00';
  filterParam = '&$filter=lastUpdate ge ' + effectiveFilterDate + 'z';
}

// ── Fetch — maxPages GLOBAL ──
const endpoints = isFullSync
  ? [{ endpoint: 'tickets/past', orderBy: 'id asc', label: 'FULL_PAST' }, { endpoint: 'tickets', orderBy: 'lastUpdate asc', label: 'FULL_RECENT' }]
  : [{ endpoint: 'tickets/past', orderBy: 'id asc', label: 'INCR_PAST' }, { endpoint: 'tickets', orderBy: 'lastUpdate asc', label: 'INCR_RECENT' }];

let fatalError = false;
const ticketIds = [];
let hitPageLimit = false;
let globalPageCount = 0;

for (const ep of endpoints) {
  if (fatalError || timedOut) break;
  currentEndpoint = ep.endpoint;

  for (let page = 0; page < 999; page++) {
    if (globalPageCount >= maxPages) { hitPageLimit = true; break; }
    if (isTimedOut()) { timedOut = true; hitPageLimit = true; break; }

    const result = await fetchPage(ep.endpoint, ep.orderBy, filterParam, ep.label, page);
    globalPageCount++;

    if (result.fatal) { fatalError = true; totalErrors++; break; }
    if (result.retryAfter) { totalErrors++; break; }
    if (!result.ok) { totalErrors++; if (totalErrors >= 3) break; continue; }
    if (result.tickets.length === 0) break;

    totalTickets += result.tickets.length;
    for (const t of result.tickets) {
      ticketIds.push(t.id);
      const dt = (t.lastUpdate || t.createdDate || '').substring(0, 10);
      if (dt && (!lastTicketDate || dt > lastTicketDate)) lastTicketDate = dt;
    }

    // Persist to DB
    if (sdkAvailable && sdk && pjId) {
      const n = await persistTickets(result.tickets);
      ticketsPersisted += n;
    }

    // Live progress every 2 pages
    if (globalPageCount % 2 === 0 || result.tickets.length < pageSize) {
      await setLiveProgress({
        stage: 'FETCHING', tickets: totalTickets, pages: globalPageCount,
        endpoint: ep.endpoint, lastTicketDate: lastTicketDate || '',
        persisted: ticketsPersisted,
        message: totalTickets + ' tickets (' + globalPageCount + '/' + maxPages + ' pag) — ' + ep.label
      });
    }

    if (result.tickets.length < pageSize) break;
    await new Promise(r => setTimeout(r, 5000));
  }

  if (timedOut) break;
}

// ═══ POINTER ADVANCEMENT ═══
let pointerAdvanced = false;
let newStartDate = null;
let pointerError = null;
let oldStartDate = null;

const syncSuccess = !fatalError && totalTickets > 0;

if (syncSuccess && lastTicketDate && sdkAvailable && sdk && pjId && !isTimedOut()) {
  await setLiveProgress({ stage: 'POINTER', tickets: totalTickets, pages: globalPageCount, endpoint: currentEndpoint, message: 'Avancando ponteiro...' });

  try {
    const lastDate = new Date(lastTicketDate);
    lastDate.setDate(lastDate.getDate() - 1);
    const candidateDate = lastDate.toISOString().slice(0, 10);
    const today = new Date().toISOString().slice(0, 10);

    let currentFromVar = '';
    let currentFromTable = '';
    let tableRecordId = null;

    try {
      const varRes = await sdk.getVariableMitra({ projectId: pjId, key: 'SYNC_START_DATE' });
      currentFromVar = (varRes && varRes.result && varRes.result.value) ? varRes.result.value : '';
    } catch (e) {}

    try {
      const tableRes = await sdk.listRecordsMitra({ projectId: pjId, tableName: 'CONFIGURACOES', page: 0, size: 100 });
      const rows = (tableRes && tableRes.content) ? tableRes.content : [];
      for (let i = 0; i < rows.length; i++) {
        if (rows[i].CHAVE === 'SYNC_START_DATE') {
          currentFromTable = rows[i].VALOR || '';
          tableRecordId = rows[i].ID;
          break;
        }
      }
    } catch (e) {}

    const currentSD = (currentFromVar && currentFromTable)
      ? (currentFromVar > currentFromTable ? currentFromVar : currentFromTable)
      : (currentFromVar || currentFromTable || startDate || '');
    oldStartDate = currentSD;

    if (candidateDate > currentSD && candidateDate <= today) {
      newStartDate = candidateDate;
      try { await sdk.setVariableMitra({ projectId: pjId, key: 'SYNC_START_DATE', value: newStartDate }); } catch (e) {}
      try {
        if (tableRecordId) {
          await sdk.patchRecordMitra({ projectId: pjId, tableName: 'CONFIGURACOES', id: tableRecordId, data: { VALOR: newStartDate } });
        }
      } catch (e) {}
      pointerAdvanced = true;
      await insertLog('DATE_ADVANCE', 'Ponteiro avancado: ' + currentSD + ' -> ' + newStartDate, 'lastTicketDate=' + lastTicketDate + ', tickets=' + totalTickets + ', persisted=' + ticketsPersisted);
    } else {
      await insertLog('DATE_NO_ADVANCE', 'Ponteiro NAO avancou: candidate=' + candidateDate + ' current=' + currentSD, '');
    }
  } catch (e) {
    pointerError = String(e.message || e).substring(0, 250);
  }
} else if (!sdkAvailable) {
  pointerError = 'SDK nao disponivel no E2B';
  oldStartDate = startDate;
}

// Clear break on success
if (syncSuccess && sdkAvailable && sdk && pjId) {
  try { await sdk.setVariableMitra({ projectId: pjId, key: 'SYNC_BREAK_DETECTED', value: 'false' }); } catch (e) {}
}

const finalMsg = fatalError ? 'Erro fatal (verifique token)'
  : timedOut ? totalTickets + ' tickets (' + ticketsPersisted + ' salvos) em ' + globalPageCount + ' pag (timeout safety)'
  : totalTickets > 0 ? totalTickets + ' tickets (' + ticketsPersisted + ' salvos) em ' + globalPageCount + ' paginas'
  : 'Nenhum ticket novo';

await insertLog('CYCLE_END', finalMsg, 'session=' + session + ',mode=' + mode + ',ptr=' + (pointerAdvanced ? newStartDate : 'nao') + ',elapsed=' + Math.round((Date.now() - execStart) / 1000) + 's');
await setLiveProgress({ stage: 'DONE', tickets: totalTickets, pages: globalPageCount, endpoint: currentEndpoint, persisted: ticketsPersisted, message: finalMsg });

return {
  success: !fatalError,
  session, mode: isFullSync ? 'FULL' : 'INCREMENTAL',
  totalTickets, totalErrors, ticketsPersisted,
  totalRequests: results.length, totalPages: globalPageCount,
  endpoint: currentEndpoint, requests: results,
  ticketIdsSample: ticketIds.slice(0, 20),
  lastTicketDate: lastTicketDate || null,
  newStartDate, pointerAdvanced, pointerError, oldStartDate,
  sdkAvailable, hitPageLimit, timedOut,
  effectiveFilterDate: effectiveFilterDate || '(none)',
  filterParam: filterParam || '(none)',
  elapsedMs: Date.now() - execStart,
  message: finalMsg
};
